226→export function isAccessAllowed(ipClass: IpClass, access: EndpointAccess): boolean {
227→  switch (access) {
228→    case 'admin':
229→      return ipClass === 'localhost'
230→    case 'write':
231→      return ipClass === 'localhost' || ipClass === 'local_network'
232→    case 'read':
233→      return true
234→    default:
235→      return false
236→  }
237→}
