189→  async delete(cwd: string, taskId: string): Promise<{ success: boolean; error?: string }> {
190→    try {
191→      await api('DELETE', `/api/tasks/${encodeURIComponent(taskId)}`, cwd)
192→      return { success: true }
193→    } catch (e) {
194→      return { success: false, error: String(e) }
195→    }
196→  }
